head.script:
/**
 * @event 
 * @name onpageload 
 * @description 화면 초기화
 */
scwin.onpageload = function () { };



/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = async function () {

    let codeOptions = [
        { grpCd: "OP239", compID: "gr_master:inspClsCd", useLocalCache: false },
        { grpCd: "OP101", compID: "gr_master:cntrSizCd", useLocalCache: false },
        { grpCd: "OP102", compID: "gr_master:cntrTypCd" },
    ];
    $c.data.setCommonCode(codeOptions);

    await scwin.submitExcute(sbm_lobran);

};



/**
 * @event 
 * @name ondataload 
 * @description 코드 완료
 */
scwin.ondataload = function () {
    scwin.globalVars();
    scwin.f_OnLoad();
};




/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {
    scwin.loginDTO = $c.data.getMemInfo();
    scwin.compnoShuttleRate = DsConstants.CMPND_SHUTTLE_RATE; //매출입항목코드(구내셔틀료)
    scwin.shuttleCheck = false;
    scwin.dt = $c.date.getServerDateTime('yyyyMMdd');
};



/**
 * @method 
 * @name f_OnLoad 
 * @description 페이지로드
 */
scwin.f_OnLoad = async function () {

    ed_stDt.setValue(scwin.dt.slice(0, 6) + '01');
    ed_endDt.setValue(scwin.dt);

    acb_lobran.setValue(scwin.loginDTO.loUpperLobranCd);

    scwin.f_getWrkPlInfo(); //해당점소의 작업장 가져오기;
    acb_wrkPlCd.addItem('전체', '', '', '');

    acb_lobran.focus();


    // test data
    // acb_lobran.setValue('6AA')
    // ed_stDt.setValue('20200101');
    // ed_endDt.setValue('20200110');

};



/**
 * @method 
 * @name f_Retrieve 
 * @description 조회 버튼 클릭시
 */
scwin.f_Retrieve = async function () {

    if (acb_lobran.getValue() == "" || acb_wrkPlCd.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        return;
    };

    let mmh = ed_mrn.getValue() + ed_msn.getValue() + ed_hsn.getValue();
    let fromDate = ed_stDt.getValue()
    let toDate = ed_endDt.getValue()

    if ((fromDate.trim() != "" && toDate.trim() == "") ||
        (fromDate.trim() == "" && toDate.trim() != "")) {

        if (fromDate.trim() == "") {
            await $c.win.alert("검사 시작일자를 입력하십시오");
            ed_stDt.focus();
            return;
        };

        if (toDate.trim() == "") {
            await $c.win.alert("검사 종료일자를 입력하십시오");
            ed_endDt.focus();
            return;
        };

        if (fromDate.trim() > toDate.trim()) {
            await $c.win.alert("조회시작일이 조회종료일보다 큽니다");
            return;
        };

    };


    if ((fromDate.trim() + toDate.trim()) == "") {
        if ((ed_blNo.getValue() + ed_cntrNo.getValue() + mmh) == "") {
            await $c.win.alert("BL번호/컨테이너번호/화물관리번호 중 한가지는 반드시 입력하십시오");
            ed_blNo.focus();
            return;
        };

        if (mmh != "") {
            let alertArray = [
                { comp: ed_mrn, part: 'MRN' },
                { comp: ed_msn, part: 'MSN' },
                { comp: ed_hsn, part: 'HSN' },
            ];

            alertArray.forEach(async (item) => {
                if (item.comp.getValue() == "") {
                    await $c.win.alert(item.part + "을 입력하십시오");
                    item.comp.focus()
                    return;
                };
            });
        };
    };

    dma_search.undo();
    dma_search.setJSON(
        {
            'branCd': acb_lobran.getValue(), //점소
            'wrkPlCd': acb_wrkPlCd.getValue(), // 작업장
            'blNo': ed_blNo.getValue(), //BL번호
            'cntrNo': ed_cntrNo.getValue(), // 컨테이너번호
            'mrn': ed_mrn.getValue(), //적하목록관리번호
            'msn': (ed_msn.getValue().trim() == "") ? 0 : ed_msn.getValue(), //msn
            'hsn': (ed_hsn.getValue().trim() == "") ? 0 : ed_hsn.getValue(), //hsn
            'stDt': fromDate,
            'endDt': toDate,
            'selpchItemCd': acb_selpchItemCd.getValue(),
        }
    );

    //hidden value  setting;
    scwin.h_wrkPlCd = acb_wrkPlCd.getValue();
    scwin.h_blNo = ed_blNo.getValue();
    scwin.h_mrn = ed_mrn.getValue();
    scwin.h_msn = ed_msn.getValue();
    scwin.h_hsn = ed_hsn.getValue();

    scwin.submitExcute(sbm_ret);

};



/**
 * @method 
 * @name f_Retrieve 
 * @description 저장
 */
scwin.f_Save = async function () {

    if (ds_master.getModifiedIndex().length == 0) return;

    const retValidChk = await scwin.f_Check();
    if (!retValidChk) {
        scwin.shuttleCheck = false;
        return;
    }

    await scwin.submitExcute(sbm_save);

};



/**
 * @method 
 * @name f_Check 
 * @description 저장시 유효성검사
 */
scwin.f_Check = async function () {

    let shuttleRate = 0, yardCgshfRate = 0;
    let rowCnt = ds_master.getRowCount();
    let targetData = ds_UnitySelling.getRowJSON(0);

    for (let i = 0; i < rowCnt; i++) {
        let rowData = ds_master.getRowJSON(i);

        ds_master.setCellData(i, "cmpndCgshfYn", rowData.cmpndCgshfYn);
        ds_master.setCellData(i, "cmpndCgshfYn", rowData.cmpndCgshfYn);
        ds_master.setCellData(i, "cmpndCgshfYn", rowData.cmpndCgshfYn);

        if (ds_master.getRowStatusValue(i) == 2) {
            ds_master.setCellData(i, "sellItemCd", (rowData.inspClsCd == "01") ? "0028" : "0160");
        };

        if (rowData.inspDt == "") {
            await $c.win.alert("검사일자를 입력하십시오");
            gr_master.setFocusedCell(i, "inspDt");
            return false;
        };

        if (rowData.inspClsCd == "") {
            await $c.win.alert("검사구분를 입력하십시오");
            gr_master.setFocusedCell(i, "inspClsCd");
            return false;
        };


        if (rowData.cntrNo == "") {
            await $c.win.alert("컨테이너 정보를 조회하십시오");
            gr_master.setFocusedCell(i, "cntrNo");
            return false;
        };

        if (rowData.cmpndCgshfYn != 0) {
            if (rowData.pchsClntNm == "") {
                await $c.win.alert(i + "번째 자료가 구내이적되었으나, 매입거래처가 입력되지 않았습니다\n매입거래처를 입력하십시오");
                return false;
            };
        };

        if (rowData.cmpndCgshfYn == 0) {
            if (rowData.pchsClntNm != "") {
                await $c.win.alert(i + "번째 자료가 매입거래처가 입력되었으나, 구내이적이 선택되지 않았습니다\n구내이적여부를 선택하십시오");
                return false;
            };
        };


        if (ds_master.getRowStatusValue(i) == 2 && rowData.chk == 0) {
            if (rowData.lineCd == "") {
                await $c.win.alert("LINE을 입력하십시오");
                gr_master.setFocusedCell(i, "lineCd");
                return false;
            };

            if (rowData.vsslCd == "") {
                await $c.win.alert("선박코드를 입력하십시오");
                gr_master.setFocusedCell(i, "vsslCd");
                return false;
            };

            if (rowData.portCd == "") {
                await $c.win.alert("항구코드를 입력하십시오");
                gr_master.setFocusedCell(i, "portCd");
                return false;
            };

            if (rowData.portcnt == "") {
                await $c.win.alert("항차를 입력하십시오");
                gr_master.setFocusedCell(i, "portcnt");
                return false;
            };

            ds_master.setCellData(i, "fullEmptyClsCd", "F");
        };


        if (rowData.inspClsCd == "02") { //식물검사 선택시
            if ([1, 2].includes(ds_master.getRowStatusValue(i))) { //insert, update 인 경우
                scwin.shuttleCheck = true;
                scwin.f_retrieveSendOutInspectionSelling(i, "cbm"); // 등록되어 있는 구내 셔틀료를 가져온다. 

                shuttleRate = rowData.cmpndShuttleRate; // 입력한 구내셔틀료

                //구내셔틀료는  0원이거나 TB_LO410에 등록한 값이여야한다. (20이면 27,600원, 40이면 39,460) - 2012.08.24
                if (shuttleRate != targetData["comnTrf1"]) {
                    if (shuttleRate != 0) {
                        await $c.win.alert("구내셔틀료을(를) 잘못 입력 하셨습니다.");
                        return false;
                    };
                };

                if (rowData.wrkPlCd == "6C01") {
                    scwin.f_retrieveSendOutInspectionSelling(i, "cbm");
                    yardCgshfRate = rowData.yardCgshfRate; // 입력한 장치장이적료

                    if (targetData["sellItemCd"] == "0002" &&
                        yardCgshfRate != targetData["comnTrf1"] &&
                        yardCgshfRate != 0) {
                        await $c.win.alert("장치장이적료(를) 잘못 입력 하셨습니다.");
                        return false;
                    };
                };
            };
        };


        if (![0, 3].includes(ds_master.getRowStatusValue(i))) { //노멀 / 삭제가 아닌 경우;
            if (rowData.newSealNo == "") {
                await $c.win.alert("변경 봉인번호를 입력하십시오");
                gr_master.setFocusedCell(i, "newSealNo");
                return false;
            };
        };

        if (rowData.arrvlportDtm == "") {
            ds_master.setCellData(i, "arrvlportDtm", scwin.dt);
        };
    };

    return true;

};



/**
 * @method 
 * @name f_getWrkPlInfo 
 * @description 작업장 콤보 조회(점소콤보가 선택되면 해당 점소의  작업장을 조회한다.
 */
scwin.f_getWrkPlInfo = function () {

    if (acb_lobran.getValue() == "") return;

    sbm_wrkpl.action = "/cm.zz.RetrieveCommonPopupCMD.do" +
        "?sysCd=CommonEBC" +
        "&queryId=retrieveWrkPlInfo" +
        "&param1=" +
        "&param2=" +
        "&param3=" +
        "&param4=" + acb_lobran.getValue() +
        "&param5=" +
        "&param6=" + "2" + /* CY & CFS */
        "&param7=" +
        "&param8=" +
        "&param9=" +
        "&param10=";

    scwin.submitExcute(sbm_wrkpl);

};



/**
 * @method 
 * @name f_containerInfo 
 * @description 컨테이너 번호를 입력 후, 해당 컨테이너 정보를 조회한다
 * @param {number} row
 * @param {string} cntrNo
 */
scwin.f_containerInfo = async function (row, cntrNo) {

    if (cntrNo == "") return;

    ds_master.setCellData(row, "chk", 0);

    let rowData = ds_master.getRowJSON(row);

    let data = {
        'cntrNo': cntrNo,
        'blNo': ed_blNo.getValue(),
        'IO': ["01", "02"].includes(rowData.inspClsCd) ? 'I' : 'O',
        'wrkPlCd': scwin.h_wrkPlCd.slice(1, 2) == "C" ? scwin.h_wrkPlCd : '',
        'mrn': ed_mrn.getValue(),
        'msn': ed_msn.getValue() == "" ? 0 : ed_msn.getValue(),
        'hsn': ed_hsn.getValue() == "" ? 0 : ed_hsn.getValue(),
    };

    let options = {
        'type': 'browserPopup',
        'width': '1210px',
        'height': '486px',
        'popupName': '컨테이너정보조회',
    };

    let url = '/ui/ds/op/wrkrslts/cywrkrslts/op_301_01_38p.xml';
    let ret = await $c.win.openPopup(url, options, data);


    if (ret == null || ret[0] == 'N/A' || ret[0] == '') {
        rowData.commCd = "";
        rowData.vsslCd = "";
        rowData.shpCoClntNo = "";
        rowData.portcnt = "";
        rowData.portCd = "";
        rowData.lineCd = "";
        rowData.line = "";
        rowData.mrn = "";
        rowData.msn = "";
        rowData.hsn = "";
        rowData.blNo = "";
        rowData.arrvlportDtm = "";
        rowData.exstSealNo = "";
        rowData.sfe = "";

        ds_master.setRowJSON(row, rowData, true);

    } else {
        if (ret[6] == "") {
            await $c.win.alert("라인거래처정보가 없어 세관검사등록을 할 수 없습니다");
            rowData.cntrNo = "";
            return;
        };

        rowData.cntrNo = ret[0];
        rowData.cntrSizCd = ret[1];
        rowData.cntrTypCd = ret[2];
        rowData.fullEmptyClsCd = "F"; //ret[3];
        rowData.commCd = ret[4];
        rowData.vsslCd = ret[5];
        rowData.shpCoClntNo = ret[6];
        rowData.portcnt = ret[7];
        rowData.portCd = ret[8];
        rowData.lineCd = ret[9];
        rowData.line = ret[9];
        rowData.mrn = ret[10];
        rowData.msn = ret[11];
        rowData.hsn = ret[12];
        rowData.blNo = ret[13];
        rowData.arrvlportDtm = ret[14];
        rowData.exstSealNo = ret[15];
        rowData.bookingNo = ret[16];
        rowData.sfe = ret[1] + ret[3];
        rowData.chk = 1; //팝업을 통해서 컨테이너를 조회한 경우;

        ds_master.setRowJSON(row, rowData, true);

        scwin.f_retrieveSendOutInspectionSelling(row, "cbm");
    };

};



/**
 * @method 
 * @name f_retrieveSendOutInspectionSelling 
 * @description
 * @param {number} row
 * @param {string} colid
 */
scwin.f_retrieveSendOutInspectionSelling = async function (row, colid) {

    let rowData = ds_master.getRowJSON(row);

    if (rowData.inspDt == "" || rowData.inspClsCd == "" || rowData.commCd == "") return;

    dma_search2.setEmptyValue();

    dma_search2.setJSON({
        "sellItemCd": rowData.inspClsCd == "01" ? "0028" : "0160",
        "cbm": rowData.cbm,
        "sellVol": rowData.cbm,
        "sellCommNo": rowData.cntrNo,
        "lineCd": rowData.lineCd,
        "rsltsStdDt": rowData.inspDt,
        "wrkStDt": rowData.inspDt,
        "onWrkPlCd": scwin.h_wrkPlCd,
        "offWrkPlCd": scwin.h_wrkPlCd,
        "cntrSizCd": rowData.cntrSizCd, //체크1
        "cntrTypCd": rowData.cntrTypCd,
        "fullEmptyClsCd": rowData.fullEmptyClsCd,
        "commCd": rowData.commCd,
        "odrDt": rowData.inspDt,
        "vsslCd": rowData.vsslCd,
        "portcnt": rowData.portcnt,
        "impExpClsCd": "I",
        "bilgClntNo": rowData.bilgClntNo,
    });

    await scwin.submitExcute(sbm_ret2);

};



/**
 * @method 
 * @name f_Excel
 * @description Excel export를 실행한다;
 */
scwin.f_Excel = function () {

    if (ds_master.getRowCount() == 0) return;

    let excelName = '세관검사등록';

    let options = {
        sheetName: excelName,
        fileName: excelName + ".xlsx",
    };

    $c.data.downloadGridViewExcel(gr_master, options);

};



/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {

    const e = await $c.sbm.execute(sbmObj);

    if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
        await scwin.submitdone(e);
    };

};



//-------------------------------------------------------------------------
// GRID HANDLE;
//-------------------------------------------------------------------------

/**
 * @method 
 * @name f_addRow
 * @description 행추가;
 */
scwin.f_addRow = async function () {

    let row, rowData;

    row = ds_master.getRowPosition();
    if (row == null) return;
    rowData = ds_master.getRowJSON(row);

    if (rowData.wrkDt == "") {
        await $c.win.alert("검사일자를 입력하십시오");
        gr_master.setFocusedCell(row, "inspDt");
        return;
    };

    if (rowData.cntrNo == "") {
        await $c.win.alert("컨테이너번호를 입력하십시오");
        gr_master.setFocusedCell(row, "cntrNo");
        return;
    };

    if (rowData.inspClsCd == "") {
        await $c.win.alert("검사구분을 선택하십시오");
        gr_master.setFocusedCell(row, "inspClsCd");
        return;
    };


    // row 추가
    row = ds_master.insertRow();
    rowData = ds_master.getRowJSON(row);

    rowData.inspDt = scwin.dt;
    rowData.inspClsCd = acb_selpchItemCd.getValue() || "01";
    rowData.wrkPlCd = scwin.h_wrkPlCd; //acb_wrkPlCd.getValue();
    rowData.bizDomCd = ds_master.getCellData(row - 1, "bizDomCd");

    ds_master.setRowJSON(row, rowData, true);

    gr_master.setFocusedCell(row, 0);

};



/**
 * @method 
 * @name f_delRow
 * @description 행삭제;
 */
scwin.f_delRow = function () { 
    let focusIdx = ds_master.getRowPosition();

    if (ds_master.getRowStatus(focusIdx) != 'C') {
        ds_master.deleteRow(focusIdx);
        gr_master.setFocusedCell(focusIdx, 0);

    }else{
        ds_master.removeRow(focusIdx);
    }
};



/**
 * @method 
 * @name f_cancel
 * @description 취소
 */
scwin.f_cancel = function () {

    let focusIdx = ds_master.getRowPosition();
    switch (ds_master.getRowStatus(focusIdx)) {
        case 'C':
            ds_master.removeRow(focusIdx);
        case 'D':
        case 'R':
            ds_master.initRowStatus(focusIdx); break;

        default:
            ds_master.deleteRow(focusIdx);
            gr_master.setFocusedCell(0, 0);
            break;
    };

    gr_master.setFocusedCell(focusIdx, 0);

};



/**
 * @method 
 * @name f_FieldClear
 * @description 휴지통버튼 클릭시 조회조건 필드를 클리어 한다
 */
scwin.f_FieldClear = function () {

    $c.gus.cfInitObjects(tbl_search, null);

    ed_stDt.setValue(scwin.dt.slice(0, 6) + "01");
    ed_endDt.setValue(scwin.dt);

    acb_lobran.setValue(scwin.loginDTO.loUpperLobranCd);

    ed_blNo.setValue("");
    ed_cntrNo.setValue("");
    ed_mrn.setValue("");
    ed_msn.setValue("");
    ed_hsn.setValue("");

    scwin.f_getWrkPlInfo();

    acb_lobran.focus(); // 점소

};



/**
 * @method 
 * @name f_retrievePchsClntInfo
 * @description
 * @param {number} row
 * @param {string} pCode
 */
scwin.f_retrievePchsClntInfo = function (row, pCode) {

    let pClose = 'T', pAllSearch = 'T';
    udc_gridComCode.setSelectId('retrievePchsClntInfo');

    udc_gridComCode.cfCommonPopUp(
        (rtnList) => {
            if (rtnList != null && rtnList[0] != "N/A") {
                ds_master.setCellData(row, "pchsClntNo", rtnList[0]);
                ds_master.setCellData(row, "pchsClntNm", rtnList[1]);
            } else {
                ds_master.setCellData(row, "pchsClntNo", "");
                ds_master.setCellData(row, "pchsClntNm", "");
            }
        }
        , pCode
        , ds_master.getCellData(row, "pchsClntNm")
        , pClose
        , null, null, null, null, null
        , null, null, null, null, null
        , pAllSearch
    ); // 작업장

};



/**
 * @method 
 * @name f_retrievePopUp
 * @description line정보를 조회한다
 * @param {number} row
 * @param {string} colid
 */
scwin.f_retrievePopUp = function (row, colid, pCode) {

    let pSelectId = '', pName = '';
    let pClose = 'T', pAllSearch = 'T', pWtitleSearch = null;

    // LINE
    switch (colid) {
        case "lineCd":
            pSelectId = 'retrieveLineInfoList';
            pName = '';
            pWtitleSearch = 'LINE,LINE코드,LINE명';
            break;

        case "vsslCd":
            pSelectId = 'retrieveVsslCdInfo';
            pName = '';
            pWtitleSearch = '선박,선박코드,선박명';
            break;

        case "portCd":
            pSelectId = 'retrievePortInfo';
            pName = '';
            pWtitleSearch = '항구,항구코드,항구명';
            break;

        case "bilgClntNo":
            pSelectId = 'retrieveClntInfo';
            pName = '';
            pWtitleSearch = '청구처,청구처코드,청구처';
            break;
    };


    udc_gridComCode.setSelectId(pSelectId);
    udc_gridComCode.cfCommonPopUp(
        async (rtnList) => {
            switch (colid) {
                case "lineCd":
                    if (rtnList != null && rtnList[0] != "N/A") {
                        if (rtnList[2] != "") {
                            ds_master.setCellData(row, "lineCd", rtnList[0]);
                            ds_master.setCellData(row, "lineNm", rtnList[1]);
                            ds_master.setCellData(row, "shpCoClntNo", rtnList[2]);
                        } else {
                            await $c.win.alert("해당 Line코드는 라인거래처 정보가 없어, 세관검사 등록을 할수 없습니다");
                            ds_master.setCellData(row, "lineCd", "");
                            ds_master.setCellData(row, "lineNm", "");
                            ds_master.setCellData(row, "shpCoClntNo", "");
                            return;
                        }
                    } else {
                        ds_master.setCellData(row, "lineCd", "");
                        ds_master.setCellData(row, "lineNm", "");
                        ds_master.setCellData(row, "shpCoClntNo", "");
                    }
                    break;

                case "vsslCd":
                    if (rtnList != null && rtnList[0] != "N/A") {
                        ds_master.setCellData(row, "vsslCd", rtnList[0]);
                    } else {
                        ds_master.setCellData(row, "vsslCd", "");
                    }
                    break;

                case "portCd":
                    if (rtnList != null && rtnList[0] != "N/A") {
                        ds_master.setCellData(row, "portCd", rtnList[0]);
                    } else {
                        ds_master.setCellData(row, "portCd", "");
                    };
                    break;

                case "bilgClntNo":
                    if (rtnList != null && rtnList[0] != "N/A") {
                        ds_master.setCellData(row, "bilgClntNo", rtnList[0]);
                    } else {
                        ds_master.setCellData(row, "bilgClntNo", "");
                    }
                    break;
            };
        },
        pCode,
        pName,					// 화면에서의 ??? Name Element의	Value
        pClose,					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        null,					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        null,					// Title순서	
        null,					// 보여주는 각 컬럼들의 폭	
        null,					// 컬럼중에서 숨기는	컬럼 지정	
        null,					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        null,					// POP-UP뛰을때 원도우의	사용자 정의	폭
        null,					// POP-UP뛰을때 우도우의	사용자 정의	높이	
        null,					// 윈도우 위치 Y좌표	
        null,					// 윈도우 위치 X좌표
        null,					// 중복체크여부	("F")
        pAllSearch,					// 전체검색허용여부	("F")
        pWtitleSearch,				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
    );

};



