//-----------------------------------------------------------------------------
//   Submission event  
//-----------------------------------------------------------------------------

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {

    let submitObj = $p.getComponentById(e.id);

    switch (submitObj) {
        case sbm_ret:
            // for="tr_ret" event="OnFail()"
            if (e.responseJSON.resultDataSet[0].Code == -1) {
                dma_search.setEmptyValue();
                ds_master.removeAll();
                return;
            };

            // for="ds_master" event="OnLoadCompleted(rowCnt)"
            let rowCnt = ds_master.getRowCount();

            if (rowCnt == 0) {
                $c.gus.cfAlertMsg("[세관검사등록] " + MSG_CM_ERR_003);
            };

            gr_master.setColumnReadOnly("cntrNo", false);
            gr_master.setColumnReadOnly("inspDt", true);
            gr_master.setColumnReadOnly("inspClsCd", true);

            totalRows.setValue(rowCnt);
            gr_master.setFocusedCell(0, 'inspDt');
            break;

        case sbm_ret2:
            // for="tr_ret2" event="OnFail()"
            if (e.responseJSON.resultDataSet[0].Code == -1) {
                let focusIdx = ds_master.getRowPosition() ?? 0;

                dma_search2.setEmptyValue();
                ds_master.setCellData(focusIdx, "cbm", 0);
                ds_master.setCellData(focusIdx, "inspAmt", 0);
                ds_master.setCellData(focusIdx, "extrAmt", 0);
                ds_master.setCellData(focusIdx, "totAmt", 0);
                return;
            };

            // for="ds_UnitySelling" event="OnLoadCompleted(rowCnt)"
            if (ds_UnitySelling.getRowCount() == 0) {
                await $c.win.alert("통합매출 기본정보가 없습니다");
                return;
            };

            let focusIdx = ds_master.getRowPosition();
            let rowData = ds_master.getRowJSON(focusIdx);
            let targetData = ds_UnitySelling.getRowJSON(0);

            rowData.rsltsStdDt = targetData["rsltsStdDt"];
            rowData.onWrkPlCd = targetData["onWrkPlCd"];
            rowData.sellUpr = targetData["sellUpr"];
            rowData.sellAmt = targetData["sellAmt"];
            rowData.sellAmtFcrc = targetData["sellAmtFcrc"];
            rowData.crcCd = targetData["crcCd"];
            rowData.sellUnitCd = targetData["sellUnitCd"];
            rowData.unitClsCd = targetData["unitClsCd"];
            rowData.sellGoodsPatternCd = targetData["sellGoodsPatternCd"];
            rowData.prebilgYn = targetData["prebilgYn"];
            rowData.dcScCd = targetData["dcScCd"];
            rowData.unsettledCloseYn = targetData["unsettledCloseYn"];
            rowData.bilgTrgtYn = targetData["bilgTrgtYn"];
            rowData.sellYn = targetData["sellYn"];
            rowData.delYn = targetData["delYn"];


            /* 감사료는 = 매출금액(?) */
            if (rowData.inspClsCd == "02") { //식물검사 선택시
                if (targetData["sellItemCd"] == scwin.compnoShuttleRate) {
                    if (!scwin.shuttleCheck) {
                        rowData.cmpndShuttleRate = targetData["comnTrf1"];
                    }
                } else if (rowData.wrkPlCd != "6C01") {
                    rowData.inspAmt = targetData["sellAmt"];
                };

                if (rowData.wrkPlCd == "6C01"
                    && targetData["sellItemCd"] == "0002") {
                    rowData.yardCgshfRate = targetData["comnTrf1"];
                };

            } else {
                rowData.inspAmt = targetData["sellAmt"];
            };

            rowData.totAmt = rowData.extrAmt ?? 0
                + rowData.cmpndShuttleRate ?? 0
                + rowData.yardCgshfRate ?? 0

            rowData.cmpndShuttleRate = targetData["comnTrf1"];

            // 변경된 행 데이터를 덮어씌운다
            ds_master.setRowJSON(focusIdx, rowData, true);
            break;

        // 저장
        case sbm_save:
            // for=tr_save event=OnFail()
            if (e.responseJSON.resultDataSet[0].Code == -1) return;

            // for=tr_save event=OnSuccess()
            $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
            scwin.shuttleCheck = false;
            scwin.f_Retrieve();
            break;

        // 점소 콤보 조회
        case sbm_lobran:
            // for="co_ds_lobran" event="OnLoadCompleted(rowCnt)"
            if (ds_lobran_item.getRowCount() == 0) {
                await $c.gus.cfAlertMsg("점소 자료 조회에 실패하였습니다");
                return;
            };
            break;
        default:
            break;
    }

};









