/**
 * @event 
 * @name gr_master_ontextimageclick
 * @description inputType이 textImage인 경우 이미지가 클릭됐을 때 발생
 */
scwin.gr_master_ontextimageclick = function (rowIndex, columnIndex) {

    let colId = gr_master.getColumnID(columnIndex);
    if (gr_master.getColumnReadOnly(colId)) return;

    let rowData = ds_master.getRowJSON(rowIndex);
    let value = ds_master.getCellData(rowIndex, colId);

    switch (colId) {
        case "cntrNo": //컨테이너번호
            ds_master.setCellData(rowIndex, "cntrNo", rowData.cntrNo.toUpperCase());
            scwin.f_containerInfo(rowIndex, rowData.cntrNo);
            break;
        case "pchsClntNm": //매입거래처
            scwin.f_retrievePchsClntInfo(rowIndex, value);
            break;
        case "lineCd", "vsslCd", "portCd", "bilgClntNo":
            scwin.f_retrievePopUp(rowIndex, colId, value);
            break;
    };

};



/**
 * @event 
 * @name gr_master_oneditend
 * @description 셀의 편집이 끝난 경우 발생하며, onafteredit보다 먼저 발생
 * @param {number} rowIndex
 * @param {number} columnIndex
 * @param {string} value
 */
scwin.gr_master_oneditend = async function (rowIndex, columnIndex, value) { 

    let colId = gr_master.getColumnID(columnIndex);

    //씨비엠
    if (colId == "cbm") {
        // 검사료 부대비용이 화면에 박혀있음......... 
        // 20210504 박태홍 수정요청(6200 -> 7100) 
        // 20220104 박태홍 수정요청(7100 -> 7500) 
        // 20230622 박태홍 수정요청(7500 -> 7900)
        ds_master.setCellData(rowIndex, "extrAmt", value * 7900);
    };

    if (ds_master.getCellData(rowIndex, colId) != value) {

        //검사일자;
        if (colId == "inspDt" && value.length != 8) {
            scwin.f_retrieveSendOutInspectionSelling(rowIndex, colId);
        };

        //컨테이너번호;
        if (colId == "cntrNo") {
            ds_master.setCellData(rowIndex, "cntrNo", value.toUpperCase());
            scwin.f_containerInfo(rowIndex, value);
            if (value == "") {
                ds_master.setCellData(rowIndex, "inspAmt", 0);
                ds_master.setCellData(rowIndex, "totAmt", 0);
                ds_master.setCellData(rowIndex, "cmpndCgshfYn", "");
                ds_master.setCellData(rowIndex, "lineCd", "");
                ds_master.setCellData(rowIndex, "exstSealNo", "");
                ds_master.setCellData(rowIndex, "newSealNo", "");
                ds_master.setCellData(rowIndex, "odrNo", "");
                ds_master.setCellData(rowIndex, "blNo", "");
            };
        };


        //검사구분/cbm|| 
        if (["inspClsCd", "cbm"].includes(colId)) {
            scwin.f_retrieveSendOutInspectionSelling(rowIndex, colId);
        };


        //부대금액;
        let amtColArray = ['inspAmt', 'extrAmt', 'cmpndShuttleRate', 'fliftUseRate', 'yardCgshfRate'];
        if (amtColArray.includes(colId)) {
            let focusIdx = ds_master.getRowPosition();
            let rowData = ds_master.getRowJSON(focusIdx);

            let totAmt = 0;
            // 입력 중인 값은 데이터를 value로 받아야하기 때문에 변경
            amtColArray.some((item) => {
                // asis에선 inspAmt가 없어 무조건 -1로 나옴 동일 동작을 위해 추가
                if (ds_master.getColumnIndex(item) === undefined) {
                    totAmt = -1;
                    return true;
                };

                if (colId == item) totAmt += $c.num.parseInt(value, 0);
                totAmt += $c.num.parseInt(rowData[item], 0);
            });

            ds_master.setCellData(focusIdx, "totAmt", totAmt);
        };

        if (colId == "pchsClntNm") { //매입거래처;
            scwin.f_retrievePchsClntInfo(rowIndex, value);
        };

        if (["lineCd", "vsslCd", "portCd", "bilgClntNo"].includes(colId)) {
            scwin.f_retrievePopUp(rowIndex, colId, value);
        };
    }

};



/**
 * @event 
 * @name gr_master_oncolumnindexchange
 * @description 방향키 또는 마우스를 이용해 선택한 셀이 변경되거나, 
 * API를 이용하여 셀에 포커스를 적용해 선택된 셀이 변경되었을 때 발생
 */
scwin.gr_master_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {

    let colId = gr_master.getColumnID(columnIndex);

    if (ds_master.getRowStatusValue(rowIndex) == 2) {
        gr_master.setColumnReadOnly("cntrNo", false);
        gr_master.setColumnReadOnly("inspDt", false);
        gr_master.setColumnReadOnly("inspClsCd", false);

        if (ds_master.getCellData(rowIndex, "chk") == 0) {
            gr_master.setColumnReadOnly("lineCd", false);
            gr_master.setColumnReadOnly("vsslCd", false);
            gr_master.setColumnReadOnly("portcnt", false);
            gr_master.setColumnReadOnly("portCd", false);
        } else {
            gr_master.setColumnReadOnly("lineCd", true);
            gr_master.setColumnReadOnly("vsslCd", true);
            gr_master.setColumnReadOnly("portcnt", true);
            gr_master.setColumnReadOnly("portCd", true);
        };

    } else {
        gr_master.setColumnReadOnly("cntrNo", true);
        gr_master.setColumnReadOnly("inspDt", true);
        gr_master.setColumnReadOnly("inspClsCd", true);
        gr_master.setColumnReadOnly("lineNm", true);
        gr_master.setColumnReadOnly("vsslCd", true);
        gr_master.setColumnReadOnly("portcnt", true);
        gr_master.setColumnReadOnly("portCd", true);
    };


    if (colId == "bookingNo") {
        if (ds_master.getCellData(rowIndex, "blNo") == "") {
            gr_master.setColumnReadOnly("bookingNo", false);
        } else {
            gr_master.setColumnReadOnly("bookingNo", true);
        };
    };

    if (colId == "yardCgshfRate") {
        if (ds_master.getCellData(rowIndex, "wrkPlCd") == "6C01") {
            gr_master.setColumnReadOnly("yardCgshfRate", true);
        } else {
            gr_master.setColumnReadOnly("yardCgshfRate", false);
        };
    };

};



